parameters.jsCode:
const raw = $input.first().json;

function parseArDate(str) {
  if (!str || typeof str !== 'string') return null;
  const t = str.trim();
  const hasOffset = /[Z]$|[+-]\d{2}:\d{2}$/.test(t);
  if (hasOffset) {
    const d = new Date(t);
    return isNaN(d.getTime()) ? null : d;
  }
  const d = new Date(t.replace(' ', 'T') + '-03:00');
  return isNaN(d.getTime()) ? null : d;
}

function toISOAR(date) {
  const arDate = new Date(date.getTime() - 3 * 60 * 60 * 1000);
  const pad = n => String(n).padStart(2, '0');
  return `${arDate.getUTCFullYear()}-${pad(arDate.getUTCMonth()+1)}-${pad(arDate.getUTCDate())}T${pad(arDate.getUTCHours())}:${pad(arDate.getUTCMinutes())}:${pad(arDate.getUTCSeconds())}-03:00`;
}

let inicio = parseArDate(raw.fecha_hora_iso);
let fechaFallback = false;
if (!inicio) {
  inicio = new Date(Date.now() + 30 * 60 * 1000);
  fechaFallback = true;
}
// Corregir año si el agente generó una fecha pasada (error de corte de entrenamiento)
const ahora = new Date();
while (inicio < ahora) {
  inicio.setFullYear(inicio.getFullYear() + 1);
}

const fin = new Date(inicio.getTime() + 30 * 60 * 1000);

const phoneDigits = String(raw.whatsapp_id || '')
  .replace(/@[^@]+$/, '')
  .replace(/^WAID:/i, '')
  .replace(/\D/g, '')
  .slice(-10);

return [{
  json: {
    lead_name: raw.lead_name || '',
    confirmation_text: raw.confirmation_text || '',
    whatsapp_id: String(raw.whatsapp_id || ''),
    inicio_iso: toISOAR(inicio),
    fin_iso: toISOAR(fin),
    phone_digits: phoneDigits,
    fecha_fallback: fechaFallback
  }
}];

